import { useState, useEffect, useRef, useCallback } from 'react';
import { tokens } from '../styles/tokens';

const T = {
  text: tokens.color.text,
  textSec: tokens.color.textSecondary,
  surface: tokens.color.surface,
  surface2: tokens.color.surfaceHover,
  border: tokens.color.border,
  green: tokens.color.green,
  blue: tokens.color.blue,
  mono: tokens.font.mono,
  sans: tokens.font.sans,
};

const ROOMS = ['general', 'strategies', 'crypto', 'options', 'newbies'];

export default function ChatRoom({ open, onClose }) {
  const [room, setRoom] = useState('general');
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [online, setOnline] = useState(0);
  const wsRef = useRef(null);
  const scrollRef = useRef(null);

  const connectWs = useCallback(() => {
    const token = localStorage.getItem('aura_token') || '';
    const protocol = window.location.protocol === 'https:' ? 'wss' : 'ws';
    const host = window.location.host;
    const ws = new WebSocket(`${protocol}://${host}/api/ws/chat?room=${room}&token=${token}`);

    ws.onopen = () => { if (import.meta.env.DEV) console.log(`[Chat] Connected to #${room}`) };
    ws.onmessage = (e) => {
      const data = JSON.parse(e.data);
      if (data.type === 'history') {
        setMessages(data.messages || []);
      } else if (data.type === 'message') {
        setMessages((prev) => [...prev, data]);
      } else if (data.type === 'online') {
        setOnline(data.count);
      }
    };
    ws.onclose = () => { if (import.meta.env.DEV) console.log('[Chat] Disconnected') };
    wsRef.current = ws;
  }, [room]);

  useEffect(() => {
    if (!open) return;
    connectWs();
    return () => {
      if (wsRef.current) wsRef.current.close();
    };
  }, [open, connectWs]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const send = () => {
    if (!input.trim() || !wsRef.current) return;
    wsRef.current.send(JSON.stringify({ message: input.trim() }));
    setInput('');
  };

  if (!open) return null;

  return (
    <div style={{
      position: 'fixed', right: 0, top: 0, bottom: 0, width: 380, zIndex: 1000,
      background: T.surface, borderLeft: `1px solid ${T.border}`,
      display: 'flex', flexDirection: 'column', fontFamily: T.sans,
      boxShadow: '-4px 0 20px rgba(0,0,0,0.3)',
    }}>
      {/* Header */}
      <div style={{
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        padding: '12px 16px', borderBottom: `1px solid ${T.border}`,
      }}>
        <div>
          <span style={{ fontSize: 14, fontWeight: 700, color: T.text }}>Chat</span>
          <span style={{ fontSize: 11, color: T.green, marginLeft: 8 }}>
            {online} online
          </span>
        </div>
        <button onClick={onClose} style={{
          background: 'none', border: 'none', color: T.textSec, cursor: 'pointer', fontSize: 18,
        }}>
          &#10005;
        </button>
      </div>

      {/* Room tabs */}
      <div style={{
        display: 'flex', gap: 4, padding: '8px 12px', overflowX: 'auto',
        borderBottom: `1px solid ${T.border}`,
      }}>
        {ROOMS.map((r) => (
          <button key={r} onClick={() => setRoom(r)} style={{
            padding: '4px 10px', borderRadius: 6, fontSize: 11, fontWeight: 600, border: 'none',
            cursor: 'pointer', whiteSpace: 'nowrap',
            background: r === room ? T.blue + '22' : 'transparent',
            color: r === room ? T.blue : T.textSec,
          }}>
            #{r}
          </button>
        ))}
      </div>

      {/* Messages */}
      <div ref={scrollRef} style={{
        flex: 1, overflowY: 'auto', padding: '8px 12px',
      }}>
        {messages.length === 0 && (
          <div style={{ textAlign: 'center', color: T.textSec, fontSize: 13, marginTop: 40 }}>
            No messages yet. Start the conversation!
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} style={{ marginBottom: 8 }}>
            <span style={{ fontSize: 13, fontWeight: 700, color: T.blue }}>{m.username}</span>
            <span style={{ fontSize: 10, color: T.textSec, marginLeft: 8 }}>
              {m.time ? new Date(m.time).toLocaleTimeString() : ''}
            </span>
            <div style={{ fontSize: 13, color: T.text, marginTop: 4, lineHeight: 1.4 }}>
              {m.message}
            </div>
          </div>
        ))}
      </div>

      {/* Input */}
      <div style={{
        display: 'flex', gap: 8, padding: '8px 12px',
        borderTop: `1px solid ${T.border}`,
      }}>
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && send()}
          placeholder="Type a message..."
          style={{
            flex: 1, padding: '8px 12px', borderRadius: 6, fontSize: 13,
            background: T.surface2, border: `1px solid ${T.border}`,
            color: T.text, outline: 'none', fontFamily: T.sans,
          }}
        />
        <button onClick={send} style={{
          padding: '8px 16px', borderRadius: 6, fontSize: 13, fontWeight: 700,
          background: T.blue, color: '#fff', border: 'none', cursor: 'pointer',
        }}>Send</button>
      </div>
    </div>
  );
}
